def check_if_last_char_is_a_letter(txt):
    '''
    Create a function that returns True if the last character
    of a given string is an alphabetical character and is not
    a part of a word, and False otherwise.
    Note: "word" is a group of characters separated by space.

    Examples:
    check_if_last_char_is_a_letter("apple pie") ➞ False
    check_if_last_char_is_a_letter("apple pi e") ➞ True
    check_if_last_char_is_a_letter("apple pi e ") ➞ False
    check_if_last_char_is_a_letter("") ➞ False 
    '''

    # Check if txt is empty
    if txt == "":
        return False
    else:
        # Check if txt is a word or not
        if txt[-1] =='':
            # Check if txt is just one word or not
            if len(txt.split(' ')) > 1:
                # Check if txt is last word or not
                return txt[-2].isalpha()
            else:
                return False
        else:
            # Check if txt is just one word or not
            if len(txt.split(' ')) > 1:
                # Check if txt is last word or not
                return txt[-1].isalpha()
            else:
                return False

def check_if_last_char_is_a_letter(txt):
    '''
    Create a function that returns True if the last character
    of a given string is an alphabetical character and is not
    a part of a word, and False otherwise.
    Note: "word" is a group of characters separated by space.

    Examples:
    check_if_last_char_is_a_letter("apple pie") ➞ False
    check_if_last_char_is_a_letter("apple pi e") ➞ True
    check_if_last_char_is_a_letter("apple pi e ") ➞ False
    check_if_last_char_is_a_letter("") ➞ False 
    '''

    # Check if txt is empty
    if len(txt) == 0:
        return False
    else:
        # Check if txt is just one word and if it is, check the last letter
        if len(txt.split(' ')) == 1:
            # Check if txt is just one letter long
            if len(txt) == 1:
                return False
            # Check if txt is more than one letter long
            else:
                # Check if txt's last letter is alpha
                if txt[-1].isalpha():
                    return True
                else:
                    return False
        # Check if txt is more than one word and if it is, check the last letter
        else:
            # Check if txt's last letter is alpha
            if txt[-1].isalpha():
                return True
            else:
                return False

def file_name_check(file_name):
    """Create a function which takes a string representing a file's name, and returns
    'Yes' if the the file's name is valid, and returns 'No' otherwise.
    A file's name is considered to be valid if and only if all the following conditions 
    are met:
    - There should not be more than three digits ('0'-'9') in the file's name.
    - The file's name contains exactly one dot '.'
    - The substring before the dot should not be empty, and it starts with a letter from 
    the latin alphapet ('a'-'z' and 'A'-'Z').
    - The substring after the dot should be one of these: ['txt', 'exe', 'dll']
    Examples:
    file_name_check("example.txt") # => 'Yes'
    file_name_check("1example.dll") # => 'No' (the name should start with a latin alphapet letter)
    """

    # Check if file_name is empty
    if file_name == "":
        return "No"

    # Check if file_name is more than 3 digits
    for i in file_name:
        if i in "0123456789":
            return "No"

    # Check if file_name is one of these
    for i in file_name:
        if i in "txt":
            return "Yes"
        elif i in "exe":
            return "Yes"
        elif i in "dll":
            return "Yes"

    # Check if file_name is more than 3 digits
    for i in file_name:
        if i in "a":
            return "Yes"
        elif i in "b":
            return "Yes"
        elif i in "c":
            return "Yes"
        elif i in "d":
            return "Yes"
        elif i in "e":
            return "Yes"
        elif i in "f":
            return "Yes"
        elif i in "g":
            return "Yes"
        elif i in "h":
            return "Yes"
        elif i in "i":
            return "Yes"
        elif i in "j":
            return "Yes"
        elif i in "k":
            return "Yes"
        elif i in "l":
            return "Yes"
        elif i in "m":
            return "Yes"

